// Merge calendar and tasks data for the prompt
const calendarItems = $('Fetch Calendar').all();
const taskItems = $('Fetch Tasks').all();

const calendar = calendarItems.map(i => i.json);
const tasks = taskItems.map(i => i.json);

const today = new Date().toLocaleDateString('en-US', {
  weekday: 'long',
  year: 'numeric',
  month: 'long',
  day: 'numeric',
  timeZone: 'Asia/Jakarta'
});

let calendarText = 'No events today.';
if (calendar.length > 0) {
  calendarText = calendar.map(e => {
    if (e.is_all_day) return `- [All day] ${e.title}`;
    const start = new Date(e.start_time).toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit', hour12: false, timeZone: 'Asia/Jakarta' });
    const end = e.end_time ? new Date(e.end_time).toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit', hour12: false, timeZone: 'Asia/Jakarta' }) : '';
    return `- ${start}${end ? '-' + end : ''} ${e.title}`;
  }).join('\n');
}

let tasksText = 'No tasks due this week.';
if (tasks.length > 0) {
  tasksText = tasks.map(t => `- [${t.priority || '?'}] ${t.name} (due: ${t.due_date || 'none'}, status: ${t.status}${t.project_name ? ', project: ' + t.project_name : ''})`).join('\n');
}

const prompt = `You are Jarvis, a personal executive assistant. Generate a concise morning briefing for ${today}.

Keep it under 300 words. Use this exact numbered format:

1. Calendar overview: [Summarize today's schedule, highlight conflicts or gaps]
2. Task priorities: [Top 3-5 tasks to focus on today, by priority]
3. Alerts: [Any deadlines within 48h, overdue items, or schedule conflicts. If none, say 'No alerts.']
4. Suggested focus: [One sentence recommendation for the day]

--- DATA ---

Calendar (${calendar.length} events):
${calendarText}

Tasks (${tasks.length} items):
${tasksText}

IMPORTANT: Be concise and actionable. No fluff. If data is empty, acknowledge it briefly and suggest the user sync their data sources.`;

return [{
  json: {
    prompt,
    today,
    calendarCount: calendar.length,
    taskCount: tasks.length
  }
}];

const response = $input.first().json;
// Extract the text content from Claude's response
const briefingText = response.content?.[0]?.text || response.text || JSON.stringify(response);
const today = new Date().toISOString().split('T')[0];

return [{
  json: {
    date: today,
    briefing_text: briefingText,
    generated_at: new Date().toISOString(),
    data_sources_used: {
      calendar: true,
      notion_tasks: true,
      email: false
    }
  }
}];
